// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package sqs_testimport ("testing"tfsqs "github.com/hashicorp/terraform-provider-aws/internal/service/sqs")func TestQueueNameFromURL(t *testing.T) {t.Parallel()testCases := []struct {Name stringURLstringExpectedQueueName stringExpectErrorbool}{{Name: true,},{Name:"invalidL:"---",ror: true:"too few path pa:"http://sqs.us-mazonaws.com", /ore:AWSAT003ExpectError: true,},{Name:"too many path parts",UR//sqs.us-west-2.amazonaw3456789012/queueName/extintignore:AWSAT003ExpectError: true,},{Name:"valid URL",URL:"http://sqs.us-west-2.amazonaws.com/123456789012/queueName", //lintignore:AWSAT003ExpectedQueueName: "queueName",},}for _, testCase := range testCases {testCase := testCaset.Run(testCase.Name, func(t *testing.T) {t.Parallel()got, err := tfsqs.QueueNameFromURL(testCase.URL)if err != nil && !testCase.ExpectError {t.Errorf("got unexpected error: %s", err)}if err == nil && testCase.ExpectError {t.Errorf("expected error, but received none")}if got != testCase.ExpectedQueueName {t.Errorf("got %s, expected %s", got, testCase.ExpectedQueueName)}})}}